import React, { useState, useEffect, createContext, useContext, useCallback } from 'react';
import ReactDOM from 'react-dom/client';

// ============================================================
// OAuth Configuration
// ============================================================
const OAUTH_CONFIG = {
  clientId: process.env.REACT_APP_OAUTH_CLIENT_ID || 'your-client-id',
  redirectUri: process.env.REACT_APP_OAUTH_REDIRECT_URI || window.location.origin + '/callback',
  authorizationEndpoint: process.env.REACT_APP_AUTH_ENDPOINT || 'https://auth.example.com/authorize',
  tokenEndpoint: process.env.REACT_APP_TOKEN_ENDPOINT || 'https://auth.example.com/token',
  revokeEndpoint: process.env.REACT_APP_REVOKE_ENDPOINT || 'https://auth.example.com/revoke',
  userInfoEndpoint: process.env.REACT_APP_USERINFO_ENDPOINT || 'https://api.example.com/userinfo',
  apiBaseUrl: process.env.REACT_APP_API_BASE_URL || 'https://api.example.com',
  scopes: 'openid profile email',
};

// ============================================================
// PKCE Utilities (Security enhancement for public clients)
// ============================================================
function generateRandomString(length) {
  const array = new Uint8Array(length);
  window.crypto.getRandomValues(array);
  return Array.from(array, (byte) => byte.toString(36).padStart(2, '0')).join('').substring(0, length);
}

async function generateCodeChallenge(codeVerifier) {
  const encoder = new TextEncoder();
  const data = encoder.encode(codeVerifier);
  const digest = await window.crypto.subtle.digest('SHA-256', data);
  return btoa(String.fromCharCode(...new Uint8Array(digest)))
    .replace(/\+/g, '-')
    .replace(/\//g, '_')
    .replace(/=+$/, '');
}

// ============================================================
// Token Storage Utilities
// ============================================================
const TOKEN_KEYS = {
  accessToken: 'oauth_access_token',
  refreshToken: 'oauth_refresh_token',
  tokenType: 'oauth_token_type',
  expiresAt: 'oauth_expires_at',
  idToken: 'oauth_id_token',
  state: 'oauth_state',
  codeVerifier: 'oauth_code_verifier',
};

const tokenStorage = {
  getAccessToken: () => localStorage.getItem(TOKEN_KEYS.accessToken),
  getRefreshToken: () => localStorage.getItem(TOKEN_KEYS.refreshToken),
  getTokenType: () => localStorage.getItem(TOKEN_KEYS.tokenType) || 'Bearer',
  getExpiresAt: () => {
    const val = localStorage.getItem(TOKEN_KEYS.expiresAt);
    return val ? parseInt(val, 10) : null;
  },
  getIdToken: () => localStorage.getItem(TOKEN_KEYS.idToken),
  getState: () => localStorage.getItem(TOKEN_KEYS.state),
  getCodeVerifier: () => localStorage.getItem(TOKEN_KEYS.codeVerifier),

  setTokens: (tokenResponse) => {
    if (tokenResponse.access_token) {
      localStorage.setItem(TOKEN_KEYS.accessToken, tokenResponse.access_token);
    }
    if (tokenResponse.refresh_token) {
      localStorage.setItem(TOKEN_KEYS.refreshToken, tokenResponse.refresh_token);
    }
    if (tokenResponse.token_type) {
      localStorage.setItem(TOKEN_KEYS.tokenType, tokenResponse.token_type);
    }
    if (tokenResponse.expires_in) {
      const expiresAt = Date.now() + tokenResponse.expires_in * 1000;
      localStorage.setItem(TOKEN_KEYS.expiresAt, expiresAt.toString());
    }
    if (tokenResponse.id_token) {
      localStorage.setItem(TOKEN_KEYS.idToken, tokenResponse.id_token);
    }
  },

  setState: (state) => localStorage.setItem(TOKEN_KEYS.state, state),
  setCodeVerifier: (verifier) => localStorage.setItem(TOKEN_KEYS.codeVerifier, verifier),

  clearAll: () => {
    Object.values(TOKEN_KEYS).forEach((key) => localStorage.removeItem(key));
  },

  isTokenExpired: () => {
    const expiresAt = tokenStorage.getExpiresAt();
    if (!expiresAt) return true;
    // Consider token expired 60 seconds before actual expiry
    return Date.now() >= expiresAt - 60000;
  },

  isAuthenticated: () => {
    return !!tokenStorage.getAccessToken() && !tokenStorage.isTokenExpired();
  },
};

// ============================================================
// OAuth Service
// ============================================================
const oauthService = {
  // Initiate authorization code flow
  async initiateLogin() {
    const state = generateRandomString(32);
    const codeVerifier = generateRandomString(64);
    const codeChallenge = await generateCodeChallenge(codeVerifier);

    tokenStorage.setState(state);
    tokenStorage.setCodeVerifier(codeVerifier);

    const params = new URLSearchParams({
      response_type: 'code',
      client_id: OAUTH_CONFIG.clientId,
      redirect_uri: OAUTH_CONFIG.redirectUri,
      scope: OAUTH_CONFIG.scopes,
      state: state,
      code_challenge: codeChallenge,
      code_challenge_method: 'S256',
    });

    window.location.href = `${OAUTH_CONFIG.authorizationEndpoint}?${params.toString()}`;
  },

  // Exchange authorization code for tokens
  async exchangeCodeForTokens(code, state) {
    const savedState = tokenStorage.getState();
    if (state !== savedState) {
      throw new Error('State mismatch. Possible CSRF attack.');
    }

    const codeVerifier = tokenStorage.getCodeVerifier();
    if (!codeVerifier) {
      throw new Error('Code verifier not found. Please restart the login flow.');
    }

    const body = new URLSearchParams({
      grant_type: 'authorization_code',
      code: code,
      redirect_uri: OAUTH_CONFIG.redirectUri,
      client_id: OAUTH_CONFIG.clientId,
      code_verifier: codeVerifier,
    });

    const response = await fetch(OAUTH_CONFIG.tokenEndpoint, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded',
      },
      body: body.toString(),
    });

    if (!response.ok) {
      const errorData = await response.json().catch(() => ({}));
      throw new Error(errorData.error_description || errorData.error || 'Token exchange failed');
    }

    const tokenData = await response.json();
    tokenStorage.setTokens(tokenData);

    // Clean up state and code verifier
    localStorage.removeItem(TOKEN_KEYS.state);
    localStorage.removeItem(TOKEN_KEYS.codeVerifier);

    return tokenData;
  },

  // Refresh access token using refresh token
  async refreshAccessToken() {
    const refreshToken = tokenStorage.getRefreshToken();
    if (!refreshToken) {
      throw new Error('No refresh token available');
    }

    const body = new URLSearchParams({
      grant_type: 'refresh_token',
      refresh_token: refreshToken,
      client_id: OAUTH_CONFIG.clientId,
    });

    const response = await fetch(OAUTH_CONFIG.tokenEndpoint, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded',
      },
      body: body.toString(),
    });

    if (!response.ok) {
      tokenStorage.clearAll();
      throw new Error('Token refresh failed. Please login again.');
    }

    const tokenData = await response.json();
    tokenStorage.setTokens(tokenData);
    return tokenData;
  },

  // Revoke tokens and logout
  async logout() {
    const accessToken = tokenStorage.getAccessToken();
    const refreshToken = tokenStorage.getRefreshToken();

    try {
      if (refreshToken) {
        await fetch(OAUTH_CONFIG.revokeEndpoint, {
          method: 'POST',
          headers: {
            'Content-Type': 'application/x-www-form-urlencoded',
          },
          body: new URLSearchParams({
            token: refreshToken,
            token_type_hint: 'refresh_token',
            client_id: OAUTH_CONFIG.clientId,
          }).toString(),
        });
      }
      if (accessToken) {
        await fetch(OAUTH_CONFIG.revokeEndpoint, {
          method: 'POST',
          headers: {
            'Content-Type': 'application/x-www-form-urlencoded',
          },
          body: new URLSearchParams({
            token: accessToken,
            token_type_hint: 'access_token',
            client_id: OAUTH_CONFIG.clientId,
          }).toString(),
        });
      }
    } catch (error) {
      console.warn('Token revocation failed:', error);
    }

    tokenStorage.clearAll();
  },
};

// ============================================================
// Authenticated Fetch Wrapper
// ============================================================
async function authenticatedFetch(url, options = {}) {
  // Check if token is expired and try to refresh
  if (tokenStorage.isTokenExpired()) {
    try {
      await oauthService.refreshAccessToken();
    } catch (error) {
      tokenStorage.clearAll();
      window.location.href = '/';
      throw new Error('Session expired. Please login again.');
    }
  }

  const accessToken = tokenStorage.getAccessToken();
  const tokenType = tokenStorage.getTokenType();

  const headers = {
    ...options.headers,
    Authorization: `${tokenType} ${accessToken}`,
  };

  const response = await fetch(url.startsWith('http') ? url : `${OAUTH_CONFIG.apiBaseUrl}${url}`, {
    ...options,
    headers,
  });

  // If 401, try to refresh token and retry once
  if (response.status === 401) {
    try {
      await oauthService.refreshAccessToken();
      const newAccessToken = tokenStorage.getAccessToken();
      const retryHeaders = {
        ...options.headers,
        Authorization: `${tokenType} ${newAccessToken}`,
      };
      return fetch(url.startsWith('http') ? url : `${OAUTH_CONFIG.apiBaseUrl}${url}`, {
        ...options,
        headers: retryHeaders,
      });
    } catch (refreshError) {
      tokenStorage.clearAll();
      window.location.href = '/';
      throw new Error('Session expired. Please login again.');
    }
  }

  return response;
}

// ============================================================
// Auth Context
// ============================================================
const AuthContext = createContext(null);

function AuthProvider({ children }) {
  const [isAuthenticated, setIsAuthenticated] = useState(tokenStorage.isAuthenticated());
  const [isLoading, setIsLoading] = useState(true);
  const [user, setUser] = useState(null);
  const [error, setError] = useState(null);

  const fetchUserInfo = useCallback(async () => {
    try {
      const response = await authenticatedFetch(OAUTH_CONFIG.userInfoEndpoint);
      if (response.ok) {
        const userData = await response.json();
        setUser(userData);
      }
    } catch (err) {
      console.error('Failed to fetch user info:', err);
    }
  }, []);

  // Handle OAuth callback
  useEffect(() => {
    const handleCallback = async () => {
      const urlParams = new URLSearchParams(window.location.search);
      const code = urlParams.get('code');
      const state = urlParams.get('state');
      const errorParam = urlParams.get('error');
      const errorDescription = urlParams.get('error_description');

      if (errorParam) {
        setError(errorDescription || errorParam);
        setIsLoading(false);
        // Clean URL
        window.history.replaceState({}, document.title, window.location.pathname);
        return;
      }

      if (code && state) {
        try {
          await oauthService.exchangeCodeForTokens(code, state);
          setIsAuthenticated(true);
          setError(null);
          await fetchUserInfo();
        } catch (err) {
          setError(err.message);
          setIsAuthenticated(false);
        }
        // Clean URL
        window.history.replaceState({}, document.title, '/');
      } else if (tokenStorage.isAuthenticated()) {
        setIsAuthenticated(true);
        await fetchUserInfo();
      }

      setIsLoading(false);
    };

    handleCallback();
  }, [fetchUserInfo]);

  // Token expiry checker
  useEffect(() => {
    if (!isAuthenticated) return;

    const interval = setInterval(() => {
      if (tokenStorage.isTokenExpired()) {
        oauthService.refreshAccessToken().catch(() => {
          setIsAuthenticated(false);
          setUser(null);
          tokenStorage.clearAll();
        });
      }
    }, 60000); // Check every minute

    return () => clearInterval(interval);
  }, [isAuthenticated]);

  const login = useCallback(async () => {
    setError(null);
    await oauthService.initiateLogin();
  }, []);

  const logout = useCallback(async () => {
    await oauthService.logout();
    setIsAuthenticated(false);
    setUser(null);
    setError(null);
  }, []);

  const value = {
    isAuthenticated,
    isLoading,
    user,
    error,
    login,
    logout,
    authenticatedFetch,
  };

  return React.createElement(AuthContext.Provider, { value }, children);
}

function useAuth() {
  const context = useContext(AuthContext);
  if (!context) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
}

// ============================================================
// Simple Router
// ============================================================
function useRoute() {
  const [path, setPath] = useState(window.location.pathname);

  useEffect(() => {
    const handlePopState = () => setPath(window.location.pathname);
    window.addEventListener('popstate', handlePopState);
    return () => window.removeEventListener('popstate', handlePopState);
  }, []);

  const navigate = useCallback((newPath) => {
    window.history.pushState({}, '', newPath);
    setPath(newPath);
  }, []);

  return { path, navigate };
}

